/* Solaris AaaS OS — Design Tokens
   Smart Sobriety · Biomimicry · Solarpunk · Bare Metal */

@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,500;0,600;0,700;1,400&family=Urbanist:wght@300;400;500;600;700;800&family=Inter:wght@300;400;500;600;700&family=JetBrains+Mono:wght@400;500;600&display=swap');

:root {
  /* ── Solarpunk Neon ─────────────────────────────────── */
  --neon: #DEFF9A;
  --neon-deep: #C8EE7C;
  --neon-glow: rgba(222, 255, 154, 0.22);

  /* ── Command Center (Dark) ──────────────────────────── */
  --slate-950: #020617;
  --slate-900: #0f172a;
  --slate-850: #131c30;
  --slate-800: #1f2937;
  --slate-700: #334155;
  --slate-600: #475569;
  --slate-500: #64748b;
  --slate-400: #94a3b8;
  --slate-300: #cbd5e1;
  --slate-200: #e2e8f0;
  --slate-100: #f1f5f9;

  /* ── Front-Stage (Stone Light) ──────────────────────── */
  --stone-50: #FAFAF9;
  --stone-100: #f5f5f4;
  --stone-200: #e7e5e4;
  --stone-300: #d6d3d1;
  --stone-400: #a8a29e;
  --stone-500: #78716c;
  --stone-700: #44403c;
  --stone-900: #1c1917;
  --pure-white: #FFFFFF;

  /* ── Client-Stage (Vault Cream) ─────────────────────── */
  --cream: #FFFAF0;
  --cream-deep: #F5EFDF;
  --cream-ink: #2A2418;
  --cream-rule: #D9CFB6;
  --cream-muted: #6B6149;

  /* ── Domain Colors (strict mapping) ─────────────────── */
  --d-growth:  #3B82F6;
  --d-sales:   #DEFF9A;
  --d-finance: #F59E0B;
  --d-ops:     #334155;
  --d-product: #EF4444;
  --d-it:      #06B6D4;
  --d-people:  #10B981;
  --d-legal:   #0F766E;

  /* ── Type ───────────────────────────────────────────── */
  --f-serif: 'Playfair Display', 'Source Serif Pro', Georgia, serif;
  --f-display: 'Urbanist', 'Inter', system-ui, sans-serif;
  --f-body: 'Inter', system-ui, sans-serif;
  --f-mono: 'JetBrains Mono', ui-monospace, Menlo, monospace;
}

/* ── Reset within screens ─────────────────────────────── */
.solaris * {
  box-sizing: border-box;
}
.solaris {
  font-family: var(--f-body);
  font-feature-settings: "ss01", "cv11", "ss03";
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
}
.solaris button { font-family: inherit; cursor: pointer; }
.solaris input, .solaris textarea { font-family: inherit; }

/* ── Utility: domain dot ──────────────────────────────── */
.dom-dot {
  display: inline-block;
  width: 8px; height: 8px; border-radius: 99px;
  vertical-align: middle;
}

/* ── Pulse keyframes ──────────────────────────────────── */
@keyframes solaris-pulse {
  0%, 100% { opacity: 1; transform: scale(1); }
  50% { opacity: 0.65; transform: scale(0.92); }
}
@keyframes solaris-blink {
  0%, 60% { opacity: 1; }
  61%, 100% { opacity: 0; }
}
@keyframes solaris-tick {
  from { transform: translateY(0.6em); opacity: 0; }
  to { transform: translateY(0); opacity: 1; }
}
@keyframes solaris-scan {
  0% { transform: translateY(-100%); }
  100% { transform: translateY(100%); }
}

// Solaris — Design System overview card
// Shows tokens, type, colors, motif elements.

const DSOverview = () => {
  const domains = [
    ['Growth',  '#3B82F6', 'G'],
    ['Sales',   '#DEFF9A', 'S'],
    ['Finance', '#F59E0B', 'F'],
    ['Ops',     '#334155', 'O'],
    ['Product', '#EF4444', 'P'],
    ['IT',      '#06B6D4', 'I'],
    ['People',  '#10B981', 'H'],
    ['Legal',   '#0F766E', 'L'],
  ];

  const swatch = (label, hex, sub) => (
    <div style={{ display:'flex', flexDirection:'column', gap:6 }}>
      <div style={{
        height:88, borderRadius:6, background:hex,
        boxShadow:'inset 0 0 0 1px rgba(0,0,0,0.08)',
        position:'relative',
      }}>
        <div style={{
          position:'absolute', left:10, bottom:8,
          fontFamily:'var(--f-mono)', fontSize:10, letterSpacing:'0.04em',
          color: hex === '#FFFFFF' || hex === '#FAFAF9' || hex === '#FFFAF0' || hex === '#DEFF9A' ? '#1c1917' : '#fff',
          opacity: 0.85,
        }}>{hex}</div>
      </div>
      <div style={{ fontFamily:'var(--f-display)', fontSize:11, fontWeight:600, letterSpacing:'0.08em', textTransform:'uppercase', color:'#1c1917' }}>{label}</div>
      {sub && <div style={{ fontFamily:'var(--f-body)', fontSize:11, color:'#78716c' }}>{sub}</div>}
    </div>
  );

  const sec = (eyebrow, title) => (
    <div style={{ marginBottom: 18 }}>
      <div style={{ fontFamily:'var(--f-mono)', fontSize:10, letterSpacing:'0.18em', color:'#78716c', textTransform:'uppercase' }}>{eyebrow}</div>
      <div style={{ fontFamily:'var(--f-serif)', fontSize:26, color:'#1c1917', marginTop:4, lineHeight:1.1, letterSpacing:'-0.01em' }}>{title}</div>
    </div>
  );

  return (
    <div className="solaris" style={{
      width:'100%', height:'100%', overflow:'auto',
      background:'#FAFAF9',
      padding:'56px 64px',
      color:'#1c1917',
    }}>
      {/* Masthead */}
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-end', borderBottom:'1px solid #d6d3d1', paddingBottom:22, marginBottom:36 }}>
        <div>
          <div style={{ fontFamily:'var(--f-mono)', fontSize:10, letterSpacing:'0.24em', color:'#78716c', textTransform:'uppercase' }}>Stitch System · v0.4</div>
          <div style={{ fontFamily:'var(--f-serif)', fontSize:54, lineHeight:1, marginTop:8, letterSpacing:'-0.02em' }}>Solaris <span style={{ fontStyle:'italic', color:'#78716c' }}>AaaS OS</span></div>
          <div style={{ fontFamily:'var(--f-body)', fontSize:14, color:'#44403c', marginTop:10, maxWidth:540 }}>
            A design system for a silent, automated closing machine. Smart Sobriety — biomimicry meets bare-metal engineering.
          </div>
        </div>
        <div style={{ textAlign:'right', fontFamily:'var(--f-mono)', fontSize:11, color:'#78716c' }}>
          <div>03 SCREENS</div>
          <div>08 DOMAINS</div>
          <div>03 SURFACES</div>
        </div>
      </div>

      {/* Three surfaces */}
      {sec('01 / Surfaces', 'Three theaters, one machine.')}
      <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:16, marginBottom:40 }}>
        {[
          { name:'Front-Stage', bg:'#FAFAF9', card:'#FFFFFF', ink:'#1c1917', tag:'Acquisition · Light' },
          { name:'Back-Stage',  bg:'#020617', card:'#0f172a', ink:'#e2e8f0', tag:'Command · Dark' },
          { name:'Client-Stage',bg:'#FFFAF0', card:'#FFFFFF', ink:'#2A2418', tag:'Sanctuary · Cream' },
        ].map((s) => (
          <div key={s.name} style={{
            background:s.bg, padding:'22px 22px 18px', borderRadius:8,
            boxShadow:'0 1px 0 rgba(0,0,0,0.04), 0 8px 24px -12px rgba(0,0,0,0.18)',
            border:'1px solid rgba(0,0,0,0.06)',
          }}>
            <div style={{ fontFamily:'var(--f-mono)', fontSize:10, color: s.ink, opacity:0.6, letterSpacing:'0.16em', textTransform:'uppercase' }}>{s.tag}</div>
            <div style={{ fontFamily:'var(--f-serif)', fontSize:22, color:s.ink, marginTop:6, marginBottom:14, letterSpacing:'-0.01em' }}>{s.name}</div>
            <div style={{ height:46, background:s.card, borderRadius:5, border:'1px solid rgba(0,0,0,0.05)', display:'flex', alignItems:'center', padding:'0 12px', fontFamily:'var(--f-display)', fontSize:11, fontWeight:600, letterSpacing:'0.08em', color:s.ink, textTransform:'uppercase' }}>
              <span style={{ opacity:0.5 }}>Card · Elevated</span>
            </div>
          </div>
        ))}
      </div>

      {/* Domain colors */}
      {sec('02 / Domains', 'Eight categorical signals.')}
      <div style={{ display:'grid', gridTemplateColumns:'repeat(8, 1fr)', gap:10, marginBottom:40 }}>
        {domains.map(([name, hex, k]) => (
          <div key={name}>
            <div style={{ height:64, borderRadius:4, background:hex, position:'relative', boxShadow:'inset 0 0 0 1px rgba(0,0,0,0.08)' }}>
              <div style={{ position:'absolute', top:6, left:8, fontFamily:'var(--f-mono)', fontSize:9, color: name === 'Sales' ? '#1c1917' : '#fff', opacity:0.85 }}>{k}</div>
            </div>
            <div style={{ fontFamily:'var(--f-display)', fontSize:10, fontWeight:700, letterSpacing:'0.1em', textTransform:'uppercase', marginTop:6 }}>{name}</div>
            <div style={{ fontFamily:'var(--f-mono)', fontSize:9, color:'#78716c', marginTop:2 }}>{hex}</div>
          </div>
        ))}
      </div>

      {/* Solar accent */}
      {sec('03 / Action', 'Solarpunk Neon — used sparingly.')}
      <div style={{ display:'grid', gridTemplateColumns:'1fr 1.4fr', gap:16, marginBottom:40 }}>
        <div style={{ background:'#020617', borderRadius:8, padding:'28px 28px', display:'flex', flexDirection:'column', justifyContent:'space-between' }}>
          <div style={{ fontFamily:'var(--f-mono)', fontSize:10, letterSpacing:'0.18em', color:'#94a3b8', textTransform:'uppercase' }}>DEFF9A · Critical Action</div>
          <button style={{
            background:'#DEFF9A', color:'#020617', border:'none', padding:'18px 24px',
            fontFamily:'var(--f-display)', fontWeight:700, fontSize:14, letterSpacing:'0.16em',
            textTransform:'uppercase', borderRadius:4,
            boxShadow:'0 0 0 1px rgba(222,255,154,0.4), 0 8px 32px -8px rgba(222,255,154,0.6)',
            marginTop:24,
          }}>Launch Audit ↗</button>
        </div>
        <div style={{ background:'#fff', borderRadius:8, border:'1px solid #e7e5e4', padding:'24px 28px' }}>
          <div style={{ fontFamily:'var(--f-body)', fontSize:12, color:'#44403c', lineHeight:1.6 }}>
            <strong style={{ fontFamily:'var(--f-display)', letterSpacing:'0.04em' }}>Rule.</strong> The neon is reserved for one button per screen — the
            outcome the system is built to extract. It never appears in headers,
            charts, hover states, or decorative chrome. If everything is the
            action, nothing is.
          </div>
          <div style={{ marginTop:18, display:'grid', gridTemplateColumns:'repeat(3, 1fr)', gap:8 }}>
            {['Audit', 'Sign Mandate', 'Disburse'].map(l => (
              <div key={l} style={{ fontFamily:'var(--f-mono)', fontSize:10, letterSpacing:'0.1em', textTransform:'uppercase', color:'#78716c', padding:'10px 12px', border:'1px dashed #d6d3d1', borderRadius:4 }}>{l}</div>
            ))}
          </div>
        </div>
      </div>

      {/* Typography */}
      {sec('04 / Type', 'Three voices.')}
      <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr', gap:16, marginBottom:40 }}>
        <div style={{ background:'#fff', borderRadius:8, padding:'24px', border:'1px solid #e7e5e4' }}>
          <div style={{ fontFamily:'var(--f-mono)', fontSize:9, color:'#78716c', letterSpacing:'0.14em', textTransform:'uppercase' }}>Playfair Display · Authority</div>
          <div style={{ fontFamily:'var(--f-serif)', fontSize:38, lineHeight:1.05, marginTop:10, letterSpacing:'-0.02em' }}>Sovereign Verification</div>
          <div style={{ fontFamily:'var(--f-serif)', fontSize:18, fontStyle:'italic', color:'#78716c', marginTop:6 }}>of Judicial Residues.</div>
        </div>
        <div style={{ background:'#fff', borderRadius:8, padding:'24px', border:'1px solid #e7e5e4' }}>
          <div style={{ fontFamily:'var(--f-mono)', fontSize:9, color:'#78716c', letterSpacing:'0.14em', textTransform:'uppercase' }}>Urbanist · Technical</div>
          <div style={{ fontFamily:'var(--f-display)', fontSize:32, fontWeight:700, marginTop:10, letterSpacing:'-0.02em' }}>$412,890.00</div>
          <div style={{ fontFamily:'var(--f-display)', fontSize:11, fontWeight:600, letterSpacing:'0.14em', textTransform:'uppercase', marginTop:4, color:'#78716c' }}>Total Funds Audited</div>
        </div>
        <div style={{ background:'#fff', borderRadius:8, padding:'24px', border:'1px solid #e7e5e4' }}>
          <div style={{ fontFamily:'var(--f-mono)', fontSize:9, color:'#78716c', letterSpacing:'0.14em', textTransform:'uppercase' }}>Inter · Body</div>
          <div style={{ fontFamily:'var(--f-body)', fontSize:13, lineHeight:1.55, marginTop:10, color:'#1c1917' }}>
            Solaris recovers unclaimed judicial surplus on a strict limited mandate. Zero upfront fees. Probate transparency. The audit precedes the conversation.
          </div>
        </div>
      </div>

      {/* Spec footer */}
      <div style={{ display:'grid', gridTemplateColumns:'repeat(4, 1fr)', gap:12, marginTop:24, paddingTop:22, borderTop:'1px solid #d6d3d1' }}>
        {[
          ['Radius', '4 · 6 · 8'],
          ['Grid', '8px base'],
          ['Elevation', '0 8px 24px -12px'],
          ['Density', 'Surgical · low chrome'],
        ].map(([k,v]) => (
          <div key={k}>
            <div style={{ fontFamily:'var(--f-mono)', fontSize:9, letterSpacing:'0.14em', textTransform:'uppercase', color:'#78716c' }}>{k}</div>
            <div style={{ fontFamily:'var(--f-display)', fontSize:14, fontWeight:600, marginTop:4 }}>{v}</div>
          </div>
        ))}
      </div>
    </div>
  );
};

window.DSOverview = DSOverview;

// SCREEN 1: FRONT-STAGE
// The Digital Garden / Acquisition
// Light mode (Stone-50). Organic, high-end consulting firm aesthetic.

const FrontStage = () => {
  const [query, setQuery] = React.useState('');
  const [tickerValue, setTickerValue] = React.useState(41289000);
  const [pulsing, setPulsing] = React.useState(false);

  // Live ticker — climbs by small increments
  React.useEffect(() => {
    const id = setInterval(() => {
      setTickerValue(v => v + Math.floor(Math.random() * 1200) + 80);
    }, 2400);
    return () => clearInterval(id);
  }, []);

  const formatted = '$' + (tickerValue / 100).toLocaleString('en-US', {
    minimumFractionDigits: 2, maximumFractionDigits: 2,
  });

  const triggerPulse = () => {
    setPulsing(true);
    setTimeout(() => setPulsing(false), 700);
  };

  // Stylized leaf SVG used as ornamental flourish
  const Leaf = ({ size=80, opacity=0.12 }) => (
    <svg viewBox="0 0 100 100" width={size} height={size} style={{ opacity }} aria-hidden="true">
      <path d="M50 8 C 25 30, 14 55, 18 88 C 50 80, 78 60, 88 22 C 70 28, 58 14, 50 8 Z"
            fill="none" stroke="#1c1917" strokeWidth="0.8" />
      <path d="M50 8 C 42 30, 36 56, 18 88" fill="none" stroke="#1c1917" strokeWidth="0.6" />
      <path d="M40 30 L 56 28 M 32 50 L 60 46 M 26 70 L 58 64" stroke="#1c1917" strokeWidth="0.5" fill="none" />
    </svg>
  );

  return (
    <div className="solaris" style={{
      width:'100%', height:'100%', overflow:'auto',
      background:'#FAFAF9',
      color:'#1c1917',
      position:'relative',
      fontFeatureSettings: '"ss01"',
    }}>
      {/* Faint grid + organic flourishes */}
      <div style={{
        position:'absolute', inset:0, pointerEvents:'none',
        backgroundImage:'linear-gradient(rgba(28,25,23,0.025) 1px, transparent 1px), linear-gradient(90deg, rgba(28,25,23,0.025) 1px, transparent 1px)',
        backgroundSize:'48px 48px',
        maskImage:'radial-gradient(ellipse 70% 70% at 50% 40%, #000 30%, transparent 80%)',
      }} />
      <div style={{ position:'absolute', top:160, left:60, pointerEvents:'none' }}><Leaf size={220} opacity={0.06} /></div>
      <div style={{ position:'absolute', bottom:80, right:60, pointerEvents:'none', transform:'scaleX(-1) rotate(20deg)' }}><Leaf size={260} opacity={0.05} /></div>

      {/* ── Minimalist Masthead ─────────────────────────── */}
      <header style={{
        display:'flex', justifyContent:'space-between', alignItems:'center',
        padding:'28px 56px',
        position:'relative', zIndex:2,
      }}>
        {/* Logo (left) */}
        <div style={{ display:'flex', alignItems:'center', gap:12 }}>
          <svg width="28" height="28" viewBox="0 0 32 32" aria-hidden="true">
            <circle cx="16" cy="16" r="6" fill="#1c1917" />
            {[...Array(8)].map((_,i) => {
              const a = (i / 8) * Math.PI * 2;
              const x1 = 16 + Math.cos(a) * 9;
              const y1 = 16 + Math.sin(a) * 9;
              const x2 = 16 + Math.cos(a) * 14;
              const y2 = 16 + Math.sin(a) * 14;
              return <line key={i} x1={x1} y1={y1} x2={x2} y2={y2} stroke="#1c1917" strokeWidth="1.4" strokeLinecap="round" />;
            })}
          </svg>
          <div>
            <div style={{ fontFamily:'var(--f-serif)', fontSize:17, letterSpacing:'-0.01em', lineHeight:1 }}>
              Alykaly <span style={{ fontStyle:'italic', color:'#78716c' }}>Holding</span>
            </div>
            <div style={{ fontFamily:'var(--f-mono)', fontSize:9, letterSpacing:'0.22em', color:'#a8a29e', textTransform:'uppercase', marginTop:3 }}>Sovereign · Solaris OS</div>
          </div>
        </div>

